function solve(m, n, waitCost) {
    const INF = Infinity;
    const dist = Array(m).fill().map(() => Array(n).fill().map(() => Array(2).fill(INF)));
    dist[0][0][1] = 1;
    const pq = [[1, 0, 0, 1]];
    const directions = [[0, 1], [1, 0]];

    while (pq.length > 0) {
        let minIndex = 0;
        for (let i = 1; i < pq.length; i++) {
            if (pq[i][0] < pq[minIndex][0]) {
                minIndex = i;
            }
        }
        const [cost, i, j, parity] = pq.splice(minIndex, 1)[0];

        if (i === m - 1 && j === n - 1) {
            return cost;
        }

        if (cost > dist[i][j][parity]) {
            continue;
        }

        if (parity === 1) {
            for (const [di, dj] of directions) {
                const ni = i + di;
                const nj = j + dj;
                if (ni >= 0 && ni < m && nj >= 0 && nj < n) {
                    const new_cost = cost + (ni + 1) * (nj + 1);
                    if (new_cost < dist[ni][nj][0]) {
                        dist[ni][nj][0] = new_cost;
                        pq.push([new_cost, ni, nj, 0]);
                    }
                }
            }
        } else {
            const new_cost = cost + waitCost[i][j];
            if (new_cost < dist[i][j][1]) {
                dist[i][j][1] = new_cost;
                pq.push([new_cost, i, j, 1]);
            }
        }
    }

    return -1;
}
